export function identifyLucidInstruction(
  instruction: { data: ReadonlyUint8Array } | ReadonlyUint8Array,
): LucidInstruction {
  const data = "data" in instruction ? instruction.data : instruction;
  if (containsBytes(data, getU8Encoder().encode(0), 0)) {
    return LucidInstruction.CreateWallet;
  }
  if (containsBytes(data, getU8Encoder().encode(1), 0)) {
    return LucidInstruction.AddIntent;
  }
  if (containsBytes(data, getU8Encoder().encode(2), 0)) {
    return LucidInstruction.AddIntentsBatch;
  }
  if (containsBytes(data, getU8Encoder().encode(3), 0)) {
    return LucidInstruction.DeactivateIntent;
  }
  if (containsBytes(data, getU8Encoder().encode(4), 0)) {
    return LucidInstruction.FreezeWallet;
  }
  if (containsBytes(data, getU8Encoder().encode(10), 0)) {
    return LucidInstruction.Propose;
  }
  if (containsBytes(data, getU8Encoder().encode(11), 0)) {
    return LucidInstruction.Approve;
  }
  if (containsBytes(data, getU8Encoder().encode(12), 0)) {
    return LucidInstruction.Cancel;
  }
  if (containsBytes(data, getU8Encoder().encode(20), 0)) {
    return LucidInstruction.Execute;
  }
  if (containsBytes(data, getU8Encoder().encode(30), 0)) {
    return LucidInstruction.Cleanup;
  }
  if (containsBytes(data, getU8Encoder().encode(228), 0)) {
    return LucidInstruction.EmitEvent;
  }
  throw new SolanaError(
    SOLANA_ERROR__PROGRAM_CLIENTS__FAILED_TO_IDENTIFY_INSTRUCTION,
    { instructionData: data, programName: "lucid" },
  );
}

